# ── INSERT FUNCTIONS ──────────────────────────────────────────────────────────

def insert_companies(cur):
    sql = """
        INSERT INTO company (
            zi_company_id, company_id, company_name, company_domain,
            company_type, company_status, is_verified,
            employee_count, employee_range, revenue_usd, revenue_range,
            ownership_type, founded_year, description, logo_url,
            city, state, country, continent,
            primary_industry, industries,
            linkedin_url, twitter_url, facebook_url,
            total_funding_amount, recent_funding_amount, recent_funding_date,
            company_funding, employee_growth, competitors,
            technologies, products
        ) VALUES (
            %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s,
            %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s
        )
        ON CONFLICT (zi_company_id) DO NOTHING
    """
    rows = [
        (
            c[0], c[1], c[2], c[3], c[4], c[5], c[6],
            c[7], c[8], c[9], c[10], c[11], c[12], c[13], c[14],
            c[15], c[16], c[17], c[18],
            c[19], c[20],
            c[21], c[22], c[23],
            c[24], c[25], c[26],
            json.dumps(c[27]), json.dumps(c[28]), json.dumps(c[29]),
            c[30], c[31],
        )
        for c in COMPANIES
    ]
    cur.executemany(sql, rows)
    print(f"  Inserted {len(rows)} companies")


def insert_decision_makers(cur):
    sql = """
        INSERT INTO decision_maker (
            zi_person_id, company_id,
            first_name, last_name, picture_url,
            job_title, department, years_of_experience,
            persona, email, phone, mobile_phone, linkedin_url
        ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
        ON CONFLICT (zi_person_id) DO NOTHING
    """
    cur.executemany(sql, DECISION_MAKERS)
    print(f"  Inserted {len(DECISION_MAKERS)} decision makers")


def insert_intents(cur):
    sql = """
        INSERT INTO company_intent (
            intent_id, company_id, category, topic,
            signal_score, signal_date, recommended_contacts
        ) VALUES (%s, %s, %s, %s, %s, %s, %s)
        ON CONFLICT (intent_id) DO NOTHING
    """
    rows = [
        (i[0], i[1], i[2], i[3], i[4], i[5], json.dumps(i[6]))
        for i in INTENTS
    ]
    cur.executemany(sql, rows)
    print(f"  Inserted {len(rows)} intent signals")


def insert_news(cur):
    sql = """
        INSERT INTO company_news (
            news_id, company_id, domain, title,
            image_url, description, category, page_date
        ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s)
        ON CONFLICT (news_id) DO NOTHING
    """
    cur.executemany(sql, NEWS)
    print(f"  Inserted {len(NEWS)} news articles")


def insert_scoops(cur):
    sql = """
        INSERT INTO company_scoop (
            scoop_id, company_id, description,
            published_date, topics, types
        ) VALUES (%s, %s, %s, %s, %s, %s)
        ON CONFLICT (scoop_id) DO NOTHING
    """
    rows = [
        (s[0], s[1], s[2], s[3], json.dumps(s[4]), json.dumps(s[5]))
        for s in SCOOPS
    ]
    cur.executemany(sql, rows)
    print(f"  Inserted {len(rows)} scoops")


# ── MAIN ──────────────────────────────────────────────────────────────────────

def main():
    dsn = get_settings().database_url_sync.replace("postgresql+psycopg://", "postgresql://")

    print("Connecting to database...")
    with psycopg.connect(dsn) as conn:
        with conn.cursor() as cur:
            print("\nSeeding SIGNAL database...")
            insert_companies(cur)
            insert_decision_makers(cur)
            insert_intents(cur)
            insert_news(cur)
            insert_scoops(cur)

    print("\nDone. All tables seeded successfully.")


if __name__ == "__main__":
    main()